package com.hospital.management.validation;import com.hospital.management.model.*;import org.junit.jupiter.api.*;import java.time.*;import static org.junit.jupiter.api.Assertions.*;class AdmissionValidatorTest{AdmissionValidator v=new AdmissionValidator();@Test void validatesAdmission(){AdmissionForm f=new AdmissionForm();f.setPatientId(1L);f.setDoctorId(2L);f.setDepartmentId(3L);f.setBedId(4L);f.setExpectedDischargeDate(LocalDate.now().plusDays(1).toString());f.setAdmissionReason("Observation required");assertFalse(v.validate(f).hasErrors());f.setPatientId(null);f.setDoctorId(null);f.setBedId(null);f.setExpectedDischargeDate(LocalDate.now().minusDays(1).toString());f.setAdmissionReason("x");assertTrue(v.validate(f).hasErrors());}@Test void validatesTransfer(){AdmissionTransferForm f=new AdmissionTransferForm();assertTrue(v.validateTransfer(f).hasErrors());f.setAdmissionId(1L);f.setTargetBedId(2L);f.setTransferReason("Clinical transfer");assertFalse(v.validateTransfer(f).hasErrors());}@Test void validatesDischarge(){DischargeForm f=new DischargeForm();f.setAdmissionId(1L);f.setDischargeSummary("ok");assertTrue(v.validateDischarge(f).hasErrors());f.setDischargeSummary("Patient discharged in stable condition");assertFalse(v.validateDischarge(f).hasErrors());}}
